('TD_AP_SDA_OCM_INTRNL_ROLE_CHNG_DN1_01406', 'o2czed1', 'AP_SDA', 'OCM_INTRNL_ROLE_CHNG_DN1', FALSE, 'D', NULL, NULL, NULL, 'CUSTOM_SQL', NULL, NULL, NULL, NULL, 'CUSTOM', 'mart_start_job_id  < (((CAST(cast((cast(CAST(DATE \'1970-01-01\' + ((%mart_start_job_id% / 86400) + 19000) AS TIMESTAMP(0)) + ((%mart_start_job_id% MOD 86400) * INTERVAL \'00:00:01\' HOUR TO SECOND) as DATE )- interval \'3\' month) as timestamp(0))  AS DATE) - 19000 ) - DATE \'1970-01-01\') * 86400 + (EXTRACT(HOUR FROM cast((cast(CAST(DATE \'1970-01-01\' + ((%mart_start_job_id% / 86400) + 19000) AS TIMESTAMP(0)) + ((%mart_start_job_id% MOD 86400) * INTERVAL \'00:00:01\' HOUR TO SECOND) as DATE )- interval \'3\' month) as timestamp(0))) * 3600) + (EXTRACT(MINUTE FROM cast((cast(CAST(DATE \'1970-01-01\' + ((%mart_start_job_id% / 86400) + 19000) AS TIMESTAMP(0)) + ((%mart_start_job_id% MOD 86400) * INTERVAL \'00:00:01\' HOUR TO SECOND) as DATE )- interval \'3\' month) as timestamp(0))) * 60) + (EXTRACT(SECOND FROM cast((cast(CAST(DATE \'1970-01-01\' + ((%mart_start_job_id% / 86400) + 19000) AS TIMESTAMP(0)) + ((%mart_start_job_id% MOD 86400) * INTERVAL \'00:00:01\' HOUR TO SECOND) as DATE )- interval \'3\' month) as timestamp(0)))))', 'mart_start_job_id  < (((CAST(cast((cast(CAST(DATE \'1970-01-01\' + ((%mart_start_job_id% / 86400) + 19000) AS TIMESTAMP(0)) + ((%mart_start_job_id% MOD 86400) * INTERVAL \'00:00:01\' HOUR TO SECOND) as DATE )- interval \'3\' month) as timestamp(0))  AS DATE) - 19000 ) - DATE \'1970-01-01\') * 86400 + (EXTRACT(HOUR FROM cast((cast(CAST(DATE \'1970-01-01\' + ((%mart_start_job_id% / 86400) + 19000) AS TIMESTAMP(0)) + ((%mart_start_job_id% MOD 86400) * INTERVAL \'00:00:01\' HOUR TO SECOND) as DATE )- interval \'3\' month) as timestamp(0))) * 3600) + (EXTRACT(MINUTE FROM cast((cast(CAST(DATE \'1970-01-01\' + ((%mart_start_job_id% / 86400) + 19000) AS TIMESTAMP(0)) + ((%mart_start_job_id% MOD 86400) * INTERVAL \'00:00:01\' HOUR TO SECOND) as DATE )- interval \'3\' month) as timestamp(0))) * 60) + (EXTRACT(SECOND FROM cast((cast(CAST(DATE \'1970-01-01\' + ((%mart_start_job_id% / 86400) + 19000) AS TIMESTAMP(0)) + ((%mart_start_job_id% MOD 86400) * INTERVAL \'00:00:01\' HOUR TO SECOND) as DATE )- interval \'3\' month) as timestamp(0)))))', NULL, NULL, NULL, NULL, 'VCM: RETENCE JE VYPNUTÁ (od 2024-04) - Předtím byla retence nastavena na tri mesice, pomoci mart_start_job_id: podminka je slozita, protoze se prevadi mart_start_job_id na datum, od ktere ho se odecitaji 3 mesice a nasledne se zase prevadi na format mart_start_job_id', 'migration_ep_opr_man_table_retention_csv', 'migration_ep_opr_man_table_retention_csv'),
